// C0650 · Leer/Escribir CSV (UTF-8) (Intermedio, IO)
import scala.io.Source
import java.nio.file.{Files, Paths}
import java.nio.charset.StandardCharsets

def solve(): Unit = {
  val lines = Source.fromFile("input.csv", "UTF-8").getLines().toList
  if (lines.isEmpty) return

  val headers = lines.head.split(",", -1).toList
  val emailIdx = headers.indexOf("Email")

  val out = new StringBuilder
  out.append(lines.head).append("\n")

  for (line <- lines.tail) {
    val cols = line.split(",", -1).toBuffer
    if (emailIdx >= 0 && emailIdx < cols.length) cols(emailIdx) = cols(emailIdx).trim.toLowerCase
    out.append(cols.mkString(",")).append("\n")
  }

  Files.write(Paths.get("output.csv"), out.toString().getBytes(StandardCharsets.UTF_8))
}

