import scala.concurrent.duration._
import scala.util.Random

def solve(maxRetries: Int = 5): Unit = {
  var attempt = 0
  var delay = 200.millis

  while (true) {
    attempt += 1
    if (Random.nextDouble() >= 0.7) return // ok
    if (attempt >= maxRetries) throw new RuntimeException("fail")
    Thread.sleep(delay.toMillis)
    delay = (delay * 2).min(5.seconds)
  }
}

