// C0665 · Binary search (iterativo) (Básico, Algoritmos)
def solve(arr: Array[Int], target: Int): Int = {
  var lo = 0
  var hi = arr.length - 1
  while (lo <= hi) {
    val mid = lo + (hi - lo) / 2
    val v = arr(mid)
    if (v == target) return mid
    if (v < target) lo = mid + 1
    else hi = mid - 1
  }
  -1
}

