// C0666 · Merge sort (Intermedio, Algoritmos)
def solve(arr: Vector[Int]): Vector[Int] = {
  if (arr.length <= 1) return arr
  val mid = arr.length / 2
  val left = solve(arr.take(mid))
  val right = solve(arr.drop(mid))

  val out = Vector.newBuilder[Int]
  var i = 0
  var j = 0
  while (i < left.length && j < right.length) {
    if (left(i) <= right(j)) { out += left(i); i += 1 }
    else { out += right(j); j += 1 }
  }
  while (i < left.length) { out += left(i); i += 1 }
  while (j < right.length) { out += right(j); j += 1 }
  out.result()
}

