// C0667 · BFS/DFS (grafo) (Intermedio, Algoritmos)
import scala.collection.mutable

def bfs(g: Map[Int, List[Int]], start: Int): List[Int] = {
  val q = mutable.Queue[Int](start)
  val seen = mutable.Set[Int](start)
  val out = mutable.ListBuffer[Int]()

  while (q.nonEmpty) {
    val v = q.dequeue()
    out += v
    for (nb <- g.getOrElse(v, Nil)) {
      if (!seen(nb)) { seen += nb; q.enqueue(nb) }
    }
  }
  out.toList
}

def dfs(g: Map[Int, List[Int]], start: Int): List[Int] = {
  val seen = mutable.Set[Int]()
  val out = mutable.ListBuffer[Int]()
  def visit(v: Int): Unit = {
    seen += v; out += v
    for (nb <- g.getOrElse(v, Nil)) if (!seen(nb)) visit(nb)
  }
  visit(start)
  out.toList
}

