// C0668 · A* (pathfinding) (Avanzado, Algoritmos)
import scala.collection.mutable

def solve(grid: Vector[Vector[Int]], start: (Int,Int), goal: (Int,Int)): List[(Int,Int)] = {
  val h = grid.length
  val w = grid.head.length
  def hcost(a:(Int,Int), b:(Int,Int)) = (a._1-b._1).abs + (a._2-b._2).abs
  def key(p:(Int,Int)) = s"${p._1},${p._2}"

  def neighbors(p:(Int,Int)) = {
    val (x,y)=p
    List((1,0),(-1,0),(0,1),(0,-1))
      .map{case(dx,dy)=>(x+dx,y+dy)}
      .filter{case(nx,ny)=> nx>=0 && ny>=0 && nx<w && ny<h && grid(ny)(nx)==0}
  }

  val open = mutable.ListBuffer[(Int,(Int,Int))]((hcost(start,goal), start))
  val came = mutable.Map[String,(Int,Int)]()
  val g = mutable.Map[String,Int](key(start)->0)

  def reconstruct(cur:(Int,Int)) = {
    var path = List(cur)
    var ck = key(cur)
    var c = cur
    while(came.contains(ck)){
      c = came(ck)
      path = c :: path
      ck = key(c)
    }
    path
  }

  while(open.nonEmpty){
    open.sortInPlaceBy(_._1)
    val cur = open.remove(0)._2
    if(cur == goal) return reconstruct(cur)
    for(nb <- neighbors(cur)){
      val nk = key(nb)
      val ng = g(key(cur)) + 1
      if(!g.contains(nk) || ng < g(nk)){
        g(nk)=ng
        came(nk)=cur
        open += ((ng + hcost(nb,goal), nb))
      }
    }
  }
  Nil
}

