// C0669 · LRU cache (Intermedio, Algoritmos)
import scala.collection.mutable

class LRU[K, V](cap: Int) {
  private val map = new java.util.LinkedHashMap[K, V](cap, 0.75f, true) {
    override def removeEldestEntry(eldest: java.util.Map.Entry[K, V]): Boolean =
      this.size() > cap
  }

  def get(k: K): Option[V] = Option(map.get(k))
  def put(k: K, v: V): Unit = map.put(k, v)
}

